function SpaceSettings({space,profile,onClose}:{space:Space;profile:UserProfile;onClose:()=>void}){const[edit,setEdit]=useState(false);const viewerIsOwner=space.ownerId===profile.id;if(edit)return <SpaceEditor profile={profile} existing={space} onClose={()=>setEdit(false)} onSaved={()=>setEdit(false)}/>;return <div className="modal panel space-settings"><header><div><p className="eyebrow">This is your shared place</p><h2>{space.emoji} {space.name}</h2><p className="settings-intro">See who belongs here, understand their access, and shape the Space when you need to.</p></div><button className="icon" aria-label="Close Space settings" onClick={onClose}><X/></button></header><section className="settings-group settings-overview"><div className="settings-heading"><div><h3>Space identity</h3><p>{space.type} · {space.memberIds.length===1?"A Space of your own":space.memberIds.length+" members"}</p></div><button className="secondary" onClick={()=>setEdit(true)}>Shape this Space</button></div></section><section className="settings-group member-settings"><div className="settings-heading"><div><h3>People in this Space</h3><p>The owner keeps final control. Admins can help edit the Space and its shared details.</p></div><span className="settings-count">{space.memberIds.length}</span></div><div className="settings-members">{space.memberIds.map(id=>{const isOwner=id===space.ownerId;const isAdmin=space.adminIds?.includes(id);const name=space.memberNames[id]||"Member";return <div className="settings-member" key={id}><span className="member-avatar" aria-hidden="true">{name.trim()[0]?.toUpperCase()||"?"}</span><div><b>{name}{id===profile.id?" · You":""}</b><small>{isOwner?"Owner · full control":isAdmin?"Admin · can help shape this Space":"Member · can participate and collaborate"}</small></div><span className={isOwner?"role-badge owner":isAdmin?"role-badge admin":"role-badge"}>{isOwner?"Owner":isAdmin?"Admin":"Member"}</span>{viewerIsOwner&&!isOwner&&<button className="link member-permission" onClick={()=>changeSpace(space.id,{adminIds:isAdmin?space.adminIds.filter(x=>x!==id):[...(space.adminIds||[]),id]})}>{isAdmin?"Make member":"Make admin"}</button>}</div>})}</div></section>{viewerIsOwner&&<section className="settings-danger" aria-labelledby="space-recovery-title"><div><h3 id="space-recovery-title">Recovery and deletion</h3><p>Deleting this Space moves it into recovery for seven days. Nothing disappears immediately.</p></div><button className="danger" onClick={async()=>{if(confirm("Move "+space.name+" to recovery?")){await softDeleteSpace(space.id);onClose()}}}><Trash2/>Move to recovery</button></section>}</div>}

function InvitePanel({space,profile,close,onContinue}:{space:Space;profile:UserProfile;close:()=>void;onContinue?:()=>void}){const[code,setCode]=useState("");const[busy,setBusy]=useState(false);const[error,setError]=useState("");const link=code?window.location.origin+"/?invite="+encodeURIComponent(code):"";const copy=async(value:string)=>{try{await navigator.clipboard.writeText(value)}catch(x){setError("Could not copy automatically. Select and copy the invite link instead.")}};const share=async()=>{const data={title:"Join "+space.name+" on SideQuest",text:"Join my "+space.name+" Space on SideQuest. Code: "+code,url:link};try{if(navigator.share)await navigator.share(data);else await copy(data.text+"\n"+link)}catch(x){if((x as Error).name!=="AbortError")setError(messageFor(x))}};const generate=async()=>{setBusy(true);setError("");try{setCode(await invite(space,profile.id))}catch(x){setError(messageFor(x))}finally{setBusy(false)}};return <div className="modal small"><header><h2>Invite to {space.emoji} {space.name}</h2><button className="icon" aria-label="Close invite" onClick={close}><X/></button></header><p>Share the link for one-tap joining, or use the short code manually. Invites expire after seven days.</p>{error&&<div className="error" role="alert">{error}</div>}{code?<div className="invite-result"><div className="code"><small>Invite code</small><b>{code}</b></div><label>Invite link<input readOnly value={link} onFocus={event=>event.currentTarget.select()}/></label><div className="invite-actions"><button className="secondary" onClick={()=>copy(link)}><ClipboardList/>Copy link</button><button className="primary" onClick={share}><Send/>Share invite</button></div></div>:<button className="primary" disabled={busy} onClick={generate}>{busy?"Creating invite…":"Generate invite link"}</button>}{onContinue&&<button className="secondary onboarding-continue" onClick={onContinue}>Continue to your first Idea</button>}</div>}
function JoinPanel({profile,close}:{profile:UserProfile;close:()=>void}){const[code,setCode]=useState("");const[error,setError]=useState("");const[busy,setBusy]=useState(false);const submit=async()=>{setBusy(true);setError("");try{await join(code,profile.id,profile.displayName);close()}catch(x){setError(messageFor(x))}finally{setBusy(false)}};return <div className="modal small"><header><h2>Join a Space</h2><button className="icon" aria-label="Close join Space" onClick={close}><X/></button></header><label>Invitation code<input value={code} autoCapitalize="characters" autoComplete="off" onChange={e=>setCode(e.target.value.toUpperCase())}/></label>{error&&<div className="error" role="alert">{error}</div>}<button className="primary" disabled={busy||!code.trim()} onClick={submit}>{busy?"Joining…":"Join Space"}</button></div>}
export default function AppV2(){const[state,setState]=useState<"loading"|"out"|"in"|"error">("loading");const[user,setUser]=useState<User|null>(null);const[profile,setProfile]=useState<UserProfile|null>(null);const[authError,setAuthError]=useState("");useEffect(()=>observeAuth(async current=>{try{if(!current){setState("out");setUser(null);setProfile(null);return}setUser(current);setProfile(await getUserProfile(current));setState("in")}catch(error){setAuthError(messageFor(error));setState("error")}},error=>{setAuthError(messageFor(error));setState("error")}),[]);if(state==="loading")return <Busy text="Opening SideQuest…"/>;if(state==="error")return <main className="auth"><div className="panel"><Logo/><h1>SideQuest could not finish signing you in.</h1><div className="error" role="alert">{authError}</div><button className="primary" onClick={()=>location.reload()}>Try again</button><button className="secondary" onClick={()=>signOutUser()}>Sign out</button></div></main>;if(state==="out"||!user||!profile)return <Auth ready={(u,p)=>{setUser(u);setProfile(p);setState("in")}}/>;return <AppShell user={user} profile={profile}/>}
